      payload: { title: "Read only" },
      causationId: null,
      correlationId: "task-readonly",
    }]);
    const expectedSchema = schema(writer);
    writer.close();
    const before = {
      bytes: sha256(databasePath),
      mtimeMs: statSync(databasePath).mtimeMs,
    };

